INSERT INTO scholarships (title, amount, type, source, description, requirements, apply_link, info_link, deadline_date) VALUES ('L&T Build India Scholarship', '₹13,400 for 24 months', 'general', 'private', 'Fully sponsored 2-year M.Tech in Construction Technology & Management (CTaM). Tuition & sponsorship fees paid by L&T. Monthly stipend of ₹13,400 for 24 months. Summer internship & final project at L&T project sites. Mentoring by L&T professionals + employment opportunity with L&T after completion', '["Final Year B.Tech/B.E Civil or Electrical Engineering students","Minimum 70% or 7.0 CGPA","Minimum 65% in 10th and 12th or Diploma"]'::jsonb, 'https://www.lntecc.com/scholarship-for-engineering-students/', 'https://www.instagram.com/p/DV3KSxLk6gH/', '"25/03/2026"'::jsonb);
